oldWay:
/* Manually counting grid line numbers */
.header  { grid-column: 1 / 3; grid-row: 1; }
.sidebar { grid-column: 1 / 2; grid-row: 2; }
.main    { grid-column: 2 / 3; grid-row: 2; }
/* Breaks silently when column count changes */

modernWay:
.page {
  grid-template-areas:
    "header  header"
    "sidebar main";
}
.header  { grid-area: header; }
.sidebar { grid-area: sidebar; }
.main    { grid-area: main; }

startingCSS:
.page {
  display: grid;
  grid-template-columns: 160px 1fr;
  grid-template-rows: 56px 1fr;
  gap: 0.75rem;
  height: 260px;
  /* Add grid-template-areas here */
}

.header  { grid-area: header; }
.sidebar { grid-area: sidebar; }
.main    { grid-area: main; }

.header {
  background: #7c3aed;
  color: white;
  border-radius: 6px;
  display: flex;
  align-items: center;
  padding: 0 1rem;
  font-weight: 600;
  font-size: 0.9rem;
}

.sidebar {
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 6px;
  padding: 1rem;
  color: #94a3b8;
  font-size: 0.85rem;
}

.main {
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 6px;
  padding: 1rem;
  color: #e2e8f0;
  font-size: 0.9rem;
}
